const cfg = $('Set Config').first().json;

const safeGet = (nodeName) => {
  try { return $(nodeName).first().json; } catch { return null; }
};
const safeGetAll = (nodeName) => {
  try { return $(nodeName).all().map(i => i.json); } catch { return []; }
};

const fmtSeconds = (secs) => {
  if (!secs || isNaN(secs)) return 'N/A';
  const s = Math.round(secs);
  if (s < 60) return s + 's';
  if (s < 3600) return Math.floor(s / 60) + 'm ' + (s % 60) + 's';
  return Math.floor(s / 3600) + 'h ' + Math.floor((s % 3600) / 60) + 'm';
};

// ── Raw data ──────────────────────────────────────────────────────────────
const summary    = safeGet('Fetch Account Summary');
const convVolume = safeGetAll('Fetch Conv Volume');      // [{timestamp, value}]
const resTrend   = safeGetAll('Fetch Resolution Trend'); // [{timestamp, value}]
// NOTE: avg_first_response_time and avg_resolution_time come from summary (no separate time-series calls)

const rawAgents  = safeGetAll('Fetch Agents List');  // direct array
const rawTeams   = safeGetAll('Fetch Teams List');   // direct array
const rawLabels  = safeGet('Fetch Labels List')?.payload ?? safeGetAll('Fetch Labels List');
const rawInboxes = safeGet('Fetch Inboxes List')?.payload ?? safeGetAll('Fetch Inboxes List');

const csatRaw    = safeGet('Fetch CSAT Reports');
const csatRows   = csatRaw?.data ?? [];

const agentOverview = safeGetAll('Fetch Agent Conv Overview');
const teamOverview  = safeGetAll('Fetch Team Conv Overview');
const inboxOverview = safeGetAll('Fetch Inbox Conv Overview');
const labelOverview = safeGetAll('Fetch Label Conv Overview');

// ── CSAT stats ────────────────────────────────────────────────────────────
const totalRatings = csatRows.length;
const sumRatings   = csatRows.reduce((a, r) => a + (r.rating ?? 0), 0);
const avgRating    = totalRatings > 0 ? (sumRatings / totalRatings).toFixed(1) : null;
const posCount     = csatRows.filter(r => r.rating >= 4).length;
const negCount     = csatRows.filter(r => r.rating <= 2).length;
const csatScore    = totalRatings > 0 ? Math.round((posCount / totalRatings) * 100) : null;

const ratingDist = [5,4,3,2,1].map(star => ({
  stars: star,
  count: csatRows.filter(r => r.rating === star).length,
  pct: totalRatings > 0
    ? Math.round(csatRows.filter(r => r.rating === star).length / totalRatings * 100)
    : 0
}));

// ── Agents ────────────────────────────────────────────────────────────────
const agentRows = rawAgents.map(agent => {
  const ov = agentOverview.find(o => o.id === agent.id) ?? {};
  const agentCsatRows = csatRows.filter(r => r.assigned_agent?.id === agent.id);
  const agentCsat = agentCsatRows.length
    ? (agentCsatRows.reduce((a,r) => a + r.rating, 0) / agentCsatRows.length).toFixed(1)
    : null;
  return {
    id:                agent.id,
    name:              agent.name,
    email:             agent.email,
    availability:      agent.availability_status,
    assigned:          ov.conversations_count ?? 0,
    resolved:          ov.resolutions_count   ?? 0,
    resolutionRate:    ov.conversations_count
      ? Math.round((ov.resolutions_count / ov.conversations_count) * 100)
      : 0,
    avgFirstResponse:  fmtSeconds(ov.avg_first_response_time),
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time),
    csatRating:        agentCsat
  };
});

// ── Teams ─────────────────────────────────────────────────────────────────
const teamRows = rawTeams.map(team => {
  const ov = teamOverview.find(o => o.id === team.id) ?? {};
  return {
    id:                team.id,
    name:              team.name,
    agentCount:        team.agents_count ?? 0,
    conversations:     ov.conversations_count ?? 0,
    resolved:          ov.resolutions_count   ?? 0,
    resolutionRate:    ov.conversations_count
      ? Math.round((ov.resolutions_count / ov.conversations_count) * 100)
      : 0,
    avgFirstResponse:  fmtSeconds(ov.avg_first_response_time),
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time)
  };
});

// ── Inboxes ───────────────────────────────────────────────────────────────
const inboxRows = (Array.isArray(rawInboxes) ? rawInboxes : []).map(inbox => {
  const ov = inboxOverview.find(o => o.id === inbox.id) ?? {};
  return {
    id:                inbox.id,
    name:              inbox.name,
    channelType:       inbox.channel_type,
    conversations:     ov.conversations_count      ?? 0,
    resolved:          ov.resolutions_count        ?? 0,
    pending:           ov.open_conversations_count ?? 0,
    avgFirstResponse:  fmtSeconds(ov.avg_first_response_time),
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time)
  };
});

// ── Labels ────────────────────────────────────────────────────────────────
const labelRows = (Array.isArray(rawLabels) ? rawLabels : []).map(label => {
  const ov = labelOverview.find(o => o.id === label.id || o.title === label.title) ?? {};
  return {
    id:                label.id,
    title:             label.title,
    color:             label.color,
    conversations:     ov.conversations_count ?? 0,
    resolved:          ov.resolutions_count   ?? 0,
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time)
  };
});

// ── Final payload ─────────────────────────────────────────────────────────
return [{
  json: {
    meta: {
      generatedAt: new Date().toISOString(),
      period: { since: cfg.since, until: cfg.until, groupBy: cfg.groupBy }
    },
    summary: {
      totalConversations: summary?.conversations_count    ?? 0,
      resolved:           summary?.resolutions_count      ?? 0,
      incomingMessages:   summary?.incoming_messages_count ?? 0,
      outgoingMessages:   summary?.outgoing_messages_count ?? 0,
      avgFirstResponse:   fmtSeconds(summary?.avg_first_response_time),
      avgResolutionTime:  fmtSeconds(summary?.avg_resolution_time),
      replyTime:          fmtSeconds(summary?.reply_time)
    },
    charts: {
      conversationVolume: convVolume.map(p => ({
        date:  new Date(p.timestamp * 1000).toLocaleDateString('en-US', { month:'short', day:'numeric' }),
        value: p.value
      })),
      resolutionTrend: resTrend.map(p => ({
        date:  new Date(p.timestamp * 1000).toLocaleDateString('en-US', { month:'short', day:'numeric' }),
        value: p.value
      }))
    },
    csat: {
      score:              csatScore,
      avgRating:          parseFloat(avgRating),
      totalResponses:     totalRatings,
      positive:           posCount,
      negative:           negCount,
      ratingDistribution: ratingDist,
      recentResponses:    csatRows.slice(0, 50).map(r => ({
        rating:    r.rating,
        feedback:  r.feedback_message,
        agent:     r.assigned_agent?.name ?? 'Unassigned',
        contact:   r.contact?.name ?? 'Unknown',
        createdAt: r.created_at
      }))
    },
    agents:  agentRows,
    teams:   teamRows,
    inboxes: inboxRows,
    labels:  labelRows
  }
}];
